{
  "verses": [
    {
      "n": 7,
      "column": "left",
      "text": "Wiꞥſch irr manni ais-\nmuhrejs/ ka es ne warru iseet/\nWiꞥſch irr manni gruhtôs Pin-\nnekfôs lizzis.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Ir jepſchu es fauzu un\nbrehzu/ tomehr Wiꞥſch aisflehds\ntawas Aufis preeſch mannas\nLuhgſchanas.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Wiꞥſch irr mannu Zelfu\naisimuhrejs ar iſzirſteem Akmi-\nxeem/ Wiꞥſch irr mannu Tekku\npawehrtijs.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Wiꞥſch irr gluhnejis us\nmanni ka Lahzis/ ka Lauwa ap-\nflehptâs Weetâs.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiꞥſch leeſ manni no\nZelta noklihſt/ Wiꞥſch irr manni\nGabbalôs faplohtijs/ Wiꞥſch irr\nmanni pohstijs.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Wiꞥſch irr fawu Stoh-\npu uhswilzis/ un manni tai Bul-\ntai par Mehrki lizzis.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Wiꞥſch irr tawas Bultas\nmannas Jhktis eefchahwis.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Es eſmu wiﬀeein man-\nneem Laudim par Apſmeekli/\nwinnu Dſeefnixa zauru Deenu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Wiꞥſch irr manni ar\nRuhftumeem pee-ehdinajs / ar\nWehrmelehem irr Wiꞥſch manni\npeedsrdinajs.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Wiꞥſch irr mannu Soh-\nbuſ ar Swirgſdeein fagruhdis/\nWiꞥſch irr manni Pelnôs ap-\nwhrtijs.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Un tu eſti mannu Dweh-\nſeli no Labklahtchanas aisdsin-\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Tad fazzijn es: Mans\nStiprums irr isnihzis/ un man-\nna Zerriba no ta KUNGA.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Peeminni mannas Beh-\ndaß/ un mannu Gruhtumu/\ntahs Wehrmeles/ un to Schulti.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Tu jo peeminnedams to\npeeminneſt/ jo manna Dwehfele\nman to peefakka.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Scho liſschu es faud\nSirđi/ tapehz gribbu es zerrecht.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Ta KUNGA Schehlastti-\nba irr/ ka mehs ne effamp a Gal-\nlain isnihkufchi/ jo Winnu Ap-\nschehloſchanahm ne irr Gals.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Tahs irr tkrihtu jaunas/\ntawa Peettzziba irr fohti leela.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Tas KUNGS irr man-\nna Dalta/ fakka manna Dweh-\ntele : Tadeht gribbu es us Wiṅ-\nnu zerrecht.\n"
    },
    {
      "n": 25,
      "column": "right",
      "text": "Tas KUNGS irr teem\nlabß/ kas us Winnu gaida/tai\nDwehſelei/ kas Winnu mekle.\n"
    },
    {
      "n": 26,
      "column": "right",
      "text": "Ta irr labba Leeta kluffa\nBuhfchanâ uhs ta KUNGA\nPalihdsibu gaidiht.\n"
    },
    {
      "n": 27,
      "column": "right",
      "text": "Taś irr labbi weenam\nZilwekam/ kad wiṅsch to Juhgú\neekſch fawas Jaunibas uefs.\n"
    },
    {
      "n": 28,
      "column": "right",
      "text": "Ka wiṅsch weentulis/ un\nkluffu irr/ kad winnam kas tohp\nuhsliſts.\n"
    },
    {
      "n": 29,
      "column": "right",
      "text": "Un fawu Mutti Piſsch-\ncôs bahſch/ tatschu wehl Zerriba.\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Un padohd tawu Waigu\ntam/ kas winnu fitt/ un nemim\ndauds Neewafchanas pretti.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
